// ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
// init()   ŌåÆ runs once on startup
// update() ŌåÆ runs every frame (dt = seconds)
// draw()   ŌåÆ runs every frame after update

let cube;

export function init() {
  cube = createCube(2, 0x0088ff, [0, 0, -5]);
  setCameraPosition(0, 3, 8);
  setCameraTarget(0, 0, 0);
  setAmbientLight(0xffffff, 0.5);
  createPointLight(0xffffff, 1.5, [3, 5, 3]);
}

export function update(dt) {
  rotateMesh(cube, 0, dt * 0.8, 0);
  if (key('ArrowLeft'))  rotateMesh(cube, 0, -dt * 2, 0);
  if (key('ArrowRight')) rotateMesh(cube, 0,  dt * 2, 0);
}

export function draw() {
  print('Hello, Nova64! ­¤Ä«', 10, 10, 0xffffff);
  print('ŌåÉ ŌåÆ to spin', 10, 26, 0x888888);
}
